INSERT INTO public.chat_faq_rules
  (scope, patterns, reply_text, priority, is_active, escalate, topic_th)
VALUES
  ('global'::public.chat_faq_scope, ARRAY['เว็บนี้คืออะไร', 'ทำอะไรได้บ้าง', 'proppiter คือ', ' livingbkk คือ', 'livingbkk เปลี่ยนเป็น', 'เวปอะไร', 'ทำงานยังไง', 'เป็นนายหน้าเหรอ', 'what is proppiter', 'ระบบทำงานยังไง'], 'PROPPITER คือแพลตฟอร์มตัวกลางด้านอสังหาริมทรัพย์สำหรับเช่า ซื้อ และขายในกรุงเทพฯ และปริมณฑลครับ เราช่วยอำนวยความสะดวกให้คุณได้พบกับทรัพย์ที่ถูกใจโดยมีทีมงานมืออาชีพคอยดูแลครับ', 100, true, false, 'แพลตฟอร์มคืออะไร'),
  ('global'::public.chat_faq_scope, ARRAY['ลงประกาศฟรีไหม', 'เสียค่าลงไหม', 'โพสต์ฟรีไหม', 'ฝากห้องมีค่าใช้จ่ายไหม', 'ลงเว็บฟรึเป่า', 'ค่าลงประกาศ', 'โพสฟรีป่าว', 'free post', 'post property', 'ฝากเช่าเสียเงินไหม'], 'การลงประกาศอสังหาริมทรัพย์บนแพลตฟอร์ม PROPPITER ไม่มีค่าใช้จ่ายเบื้องต้นครับ เราเปิดให้โพสต์ฟรีและจะมีการเก็บค่าบริการก็ต่อเมื่อการเช่าหรือขายสำเร็จแล้วเท่านั้นครับ', 80, true, false, 'ลงประกาศฟรี'),
  ('global'::public.chat_faq_scope, ARRAY['คิดค่าคอมยังไง', 'เก็บค่าคอมเท่าไหร่', 'success fee', 'ค่านายหน้าเท่าไร', 'ค่าคอมมิชชั่น', 'หักกี่เปอร์เซ็นต์', 'เสียค่านายหน้าไหม', 'commission fee', 'นายหน้ากี่เดือน', 'ค่าธรรมเนียมเว็บ'], 'ทางเราคิดค่าบริการแบบ Success Fee เมื่อมีการเช่าหรือขายสำเร็จครับ สำหรับรายละเอียดค่าคอมมิชชั่นของแต่ละทรัพย์จะถูกรวมอยู่ในราคา Net ที่แสดงบนแพลตฟอร์มเรียบร้อยแล้วครับ', 50, true, false, 'การเก็บค่าคอม'),
  ('global'::public.chat_faq_scope, ARRAY['รับโคไหม', 'รับ co ไหม', 'โคเอเจ้น', 'co-agent', 'co agent', 'รับเอเจ้นร่วมไหม', 'โคกันไหม', 'มีลูกค้ารับโคไหม', 'แบ่งคอมไหม', 'co property'], 'ยินดีครับ ทางเรารับพิจารณาการทำงานร่วมกับ Co-Agent ครับ รบกวนคุณลูกค้าทิ้งเบอร์ติดต่อหรือส่งรายละเอียดทรัพย์มาได้เลย ทีมงานจะรีบประสานงานกลับไปเพื่อคุยรายละเอียดนะครับ', 10, true, true, 'Co-Agent'),
  ('global'::public.chat_faq_scope, ARRAY['สัญญากี่ปี', 'ระยะสัญญา', 'ขั้นต่ำกี่เดือน', 'สัญญาเช่ากี่ปี', 'สัญญาเช่า', 'เช่ากี่เดือน', 'contract', 'minimum contract', 'สัญญา 1 ปี', 'อยู่สั้นได้ไหม', 'เช่ารายเดือน', 'ระยะเวลาเช่า'], 'โดยปกติสัญญาเช่าจะมีระยะเวลาขั้นต่ำ 1 ปีครับ แต่สำหรับบางทรัพย์อาจมีเงื่อนไขเพิ่มเติม หากมีข้อสงสัยเกี่ยวกับสัญญาห้องไหน แจ้งทีมงานตรวจสอบให้ได้เลยครับ', 30, true, false, 'สัญญา(ทั่วไป)'),
  ('global'::public.chat_faq_scope, ARRAY['ยกเลิกสัญญา', 'ออกก่อนสัญญา', 'ย้ายออกก่อนกำหนด', 'คืนเงินไหมถ้าออกก่อน', 'cancel contract', 'บอกเลิกสัญญา', 'break contract', 'ผิดสัญญา', 'ออกก่อน 1 ปี', 'ไม่ครบสัญญา'], 'กรณีต้องการยกเลิกสัญญาเช่าก่อนกำหนด จะเป็นไปตามเงื่อนไขที่ระบุไว้ในสัญญาครับ ซึ่งโดยทั่วไปอาจทำให้ไม่ได้รับเงินประกันคืนครับ หากมีเหตุจำเป็นลองแจ้งทีมงานเพื่อหาทางออกร่วมกันนะครับ', 20, true, true, 'ยกเลิกสัญญา'),
  ('global'::public.chat_faq_scope, ARRAY['ขั้นตอนการโอน', 'ค่าโอนใครจ่าย', 'ซื้อยังไง', 'ค่าธรรมเนียมโอน', 'โอนกรรมสิทธิ์', 'transfer fee', 'ภาษีการโอน', 'ค่าโอนคนละครึ่งไหม', 'จ่ายค่าโอน', 'ขั้นตอนการซื้อขาย'], 'สำหรับการซื้อขาย ค่าธรรมเนียมการโอนและภาษีต่างๆ จะขึ้นอยู่กับข้อตกลงระหว่างผู้ซื้อและผู้ขายครับ หากสนใจทรัพย์ใด ทีมงานจะช่วยประสานงานเรื่องเงื่อนไขและค่าใช้จ่ายในวันโอนให้ชัดเจนครับ', 20, true, true, 'โอน/ซื้อ'),
  ('global'::public.chat_faq_scope, ARRAY['yield เท่าไหร่', 'ผลตอบแทน', 'ปล่อยเช่าได้เท่าไร', 'ซื้อลงทุน', 'ลงทุนคุ้มไหม', 'rental yield', 'ROI', 'ได้กำไรกี่เปอร์เซ็น', 'เปอร์เซ็นต์ผลตอบแทน', 'ราคาประเมินปล่อยเช่า'], 'สำหรับนักลงทุน อัตราผลตอบแทน (Rental Yield) จะแตกต่างกันไปตามทำเลและสภาพโครงการครับ หากคุณลูกค้าสนใจลงทุน สามารถแจ้งโซนที่ต้องการเพื่อให้ทีมงานช่วยคัดกรองทรัพย์ที่ได้ Yield คุ้มค่าให้ได้ครับ', 40, true, false, 'yield นักลงทุน'),
  ('global'::public.chat_faq_scope, ARRAY['เปิดกี่โมง', 'เวลาทำการ', 'แอดมินตอบกี่โมง', 'เปิดถึงกี่โมง', 'working hours', 'ติดต่อได้ตอนไหน', 'ทำงานวันไหนบ้าง', 'หยุดวันอาทิตย์ไหม', 'ออฟฟิศเปิดไหม'], 'แพลตฟอร์มเราเปิดให้ค้นหาทรัพย์ได้ตลอด 24 ชั่วโมงครับ สำหรับทีมงานแอดมินพร้อมให้บริการและตอบคำถามทุกวัน ตั้งแต่เวลา 09:00 น. ถึง 18:00 น. ครับ', 100, true, false, 'เวลาทำการ'),
  ('global'::public.chat_faq_scope, ARRAY['ติดต่อแอดมิน', 'คุยกับพนักงาน', 'ขอเบอร์บริษัท', 'โทรหาใคร', 'call admin', 'ติดต่อเว็บ', 'ขอเบอร์ติดต่อกลับ', 'โทรสอบถาม', 'ต้องการความช่วยเหลือ', 'คุยกับคน'], 'สามารถฝากเบอร์โทรศัพท์และข้อซักถามไว้ในแชทนี้ได้เลยครับ ทีมงานแอดมินของ PROPPITER จะรีบติดต่อกลับไปเพื่อดูแลและให้คำปรึกษาโดยเร็วที่สุดครับ', 10, true, true, 'ติดต่อทีมงาน'),
  ('global'::public.chat_faq_scope, ARRAY['เช่าต้องใช้เอกสารอะไร', 'ใครเช่าได้บ้าง', 'เงื่อนไขการเช่า', 'ตรวจเครดิตไหม', 'tenant requirements', 'ต้องเตรียมอะไรบ้าง', 'คุณสมบัติผู้เช่า', 'เด็กอยู่ได้ไหม', 'อายุเท่าไหร่เช่าได้', 'นักศึกษาเช่าได้ไหม'], 'เบื้องต้นการเช่าจะใช้สำเนาบัตรประชาชน หรือพาสปอร์ตสำหรับชาวต่างชาติครับ บางทรัพย์อาจมีเงื่อนไขเพิ่มเติมเล็กน้อย แจ้งความต้องการมาได้เลย ทีมงานจะดูแลให้ตรงจุดครับ', 80, true, false, 'เงื่อนไขผู้เช่า'),
  ('global'::public.chat_faq_scope, ARRAY['ได้เงินประกันคืนไหม', 'ได้มัดจำคืนตอนไหน', 'คืนเงินประกันยังไง', 'หักค่าอะไรบ้าง', 'deposit refund', 'เงินมัดจำคืนไหม', 'ได้เงินคืนเมื่อไหร่', 'คืนมัดจำ', 'หักค่าทำความสะอาดไหม'], 'เงินประกันจะคืนให้เมื่อครบสัญญาและย้ายออกครับ โดยจะมีการตรวจสภาพห้อง หากไม่มีความเสียหายที่เกินกว่าการใช้งานปกติ ก็จะได้รับเงินคืนตามเงื่อนไขสัญญาครับ', 30, true, false, 'การคืนเงินประกัน'),
  ('global'::public.chat_faq_scope, ARRAY['ต่อสัญญา', 'ต่อสัญญาเช่า', 'หมดสัญญาทำไง', 'จะต่อสัญญา', 'renew contract', 'ต่ออายุ', 'ขออยู่ต่อ', 'หมดสัญญา', 'ต่อสัญญาได้ไหม'], 'หากใกล้ครบสัญญาและต้องการเช่าต่อ สามารถแจ้งทีมงาน PROPPITER ล่วงหน้า 30-60 วันได้เลยครับ ทางเราจะช่วยประสานงานเรื่องเอกสารการต่อสัญญาให้เรียบร้อยครับ', 50, true, false, 'การต่อสัญญา'),
  ('global'::public.chat_faq_scope, ARRAY['ใช้เอกสารอะไรบ้าง', 'เอกสารประกอบ', 'เตรียมเอกสารอะไร', 'documents needed', 'ต้องใช้พาสปอร์ตไหม', 'ใช้ทะเบียนบ้านไหม', 'สลิปเงินเดือน', 'ขอเอกสารอะไรบ้าง'], 'สำหรับการทำสัญญาเช่า โดยทั่วไปใช้เพียงสำเนาบัตรประชาชนตัวจริง หรือพาสปอร์ตสำหรับชาวต่างชาติครับ ส่วนการซื้อขายทีมงานจะแจ้งรายการเอกสารที่จำเป็นให้ทราบอีกครั้งครับ', 70, true, false, 'เอกสารที่ต้องใช้'),
  ('global'::public.chat_faq_scope, ARRAY['ความปลอดภัยข้อมูล', 'pdpa', 'ข้อมูลส่วนตัว', 'privacy policy', 'เก็บข้อมูลไหม', 'ลบข้อมูล', 'เอาเบอร์ไปทำอะไร', 'ความลับ', 'ข้อมูลรั่วไหม'], 'PROPPITER ให้ความสำคัญกับข้อมูลส่วนบุคคลของลูกค้าสูงสุดตามกฎหมาย PDPA ครับ ข้อมูลของคุณจะถูกเก็บรักษาเป็นความลับและใช้เพื่อการติดต่อประสานงานเรื่องอสังหาฯ เท่านั้นครับ', 100, true, false, 'นโยบายความเป็นส่วนตัว'),
  ('property'::public.chat_faq_scope, ARRAY['ราคา', 'เท่าไร', 'เท่าไหร่', 'กี่บาท', 'price', 'เท่าไร่', 'ค่าเช่าเท่าไร', 'ขายกี่บาท', 'เช่าเท่าไหร่', 'ราคาเน็ต', 'ราคาสุทธิ', 'แพงไป', 'ถูกสุดเท่าไหร่'], 'ราคาที่แสดงบนแพลตฟอร์มเป็นราคา Net สำหรับทรัพย์นี้แล้วครับ ครอบคลุมค่าใช้จ่ายตามมาตรฐานครบถ้วน หากมีรายละเอียดใดที่ไม่แน่ใจ ฝากเบอร์ไว้ให้ทีมงานอธิบายเพิ่มเติมได้เลยครับ', 10, true, false, 'ราคา/Net'),
  ('property'::public.chat_faq_scope, ARRAY['ค่าส่วนกลาง', 'รวมส่วนกลางยัง', 'cam fee', 'ค่าส่วนกลางเท่าไหร่', 'จ่ายส่วนกลางไหม', 'รวมค่าส่วนกลางไหม', 'ส่วนกลางใครจ่าย', 'ค่าบำรุงรักษา', 'common fee', 'เสียค่าส่วนกลางเพิ่มไหม'], 'โดยปกติราคาเช่าที่แสดงจะรวมค่าส่วนกลางเรียบร้อยแล้วครับ แต่หากเป็นการซื้อขาย ค่าส่วนกลางจะคิดตามตารางเมตรของห้องครับ หากอยากทราบตัวเลขเป๊ะๆ ฝากคำถามไว้ได้เลยครับ', 30, true, false, 'ค่าส่วนกลาง'),
  ('property'::public.chat_faq_scope, ARRAY['มัดจำกี่เดือน', 'เงินประกัน', 'ล่วงหน้ากี่เดือน', 'deposit', 'ประกันเท่าไหร่', 'จ่ายล่วงหน้า', 'แรกเข้ากี่บาท', 'รวมจ่ายแรกเข้า', 'ค่ามัดจำห้อง', 'มัดจำเท่าไร'], 'เงื่อนไขแรกเข้าโดยทั่วไปคือจ่ายเงินประกัน 2 เดือน และค่าเช่าล่วงหน้า 1 เดือนครับ แต่ทั้งนี้อาจมีรายละเอียดแตกต่างกันไปในบางทรัพย์ครับ', 30, true, false, 'เงินประกัน/มัดจำ'),
  ('property'::public.chat_faq_scope, ARRAY['สัตว์เลี้ยง', 'เลี้ยงหมา', 'เลี้ยงแมว', 'pet friendly', 'เลี้ยงสัตว์ได้ไหม', 'มีน้องหมา', 'สัตว์เลี้ยงได้ไหม', 'อนุญาตให้เลี้ยง', 'เลี้ยงนก', 'เลี้ยงสัตว์เล็ก'], 'คอนโดนี้อนุญาตให้เลี้ยงสัตว์ได้ครับ แต่ต้องเป็นไปตามกฎของนิติบุคคล หากไม่แน่ใจว่าเลี้ยงชนิดใดได้บ้าง หรือมีค่าธรรมเนียมสัตว์เลี้ยงไหม ฝากเบอร์ไว้ให้เจ้าหน้าที่เช็ครายละเอียดให้ชัวร์ก่อนได้ครับ', 20, true, false, 'สัตว์เลี้ยง'),
  ('property'::public.chat_faq_scope, ARRAY['ที่จอดรถ', 'มีที่จอดไหม', 'จอดรถได้กี่คัน', 'เสียค่าจอดไหม', 'parking', 'car park', 'ที่จอดรถฟรีไหม', 'จอดประจำไหม', 'มีสิทธิ์จอดรถ', 'ที่จอดเต็มไหม'], 'ทรัพย์นี้มีสิทธิ์ที่จอดรถให้ครับ แต่อาจจะต้องเช็คว่าเป็นการจอดแบบระบุตำแหน่งหรือหมุนเวียน และมีค่าสติ๊กเกอร์รายปีหรือไม่ เดี๋ยวให้ทีมงานคอนเฟิร์มรายละเอียดเชิงลึกให้นะครับ', 40, true, false, 'ที่จอดรถ'),
  ('property'::public.chat_faq_scope, ARRAY['เฟอร์นิเจอร์', 'เฟอร์ครบไหม', 'fully furnished', 'มีเฟอร์อะไรบ้าง', 'เตียงกี่ฟุต', 'แถมเฟอร์ไหม', 'มีโซฟาไหม', 'ตู้เสื้อผ้า', 'ห้องเปล่าไหม', 'แต่งครบไหม'], 'ห้องนี้ตกแต่งพร้อมเฟอร์นิเจอร์ตามภาพเลยครับ แต่เพื่อความแน่ใจในรายการเฟอร์นิเจอร์แต่ละชิ้น รบกวนคุณลูกค้าฝากเบอร์ไว้ให้ทีมงานรีเช็ครายการของจริงให้อีกครั้งเพื่อความถูกต้องนะครับ', 50, true, false, 'เฟอร์นิเจอร์'),
  ('property'::public.chat_faq_scope, ARRAY['ห้องว่างไหม', 'เข้าอยู่ได้วันไหน', 'พร้อมอยู่ไหม', 'available when', 'ย้ายเข้าได้เลยไหม', 'ว่างเมื่อไหร่', 'ยังว่างอยู่ไหม', 'ห้องนี้ว่างไหม', 'available?', 'ย้ายเข้าพรุ่งนี้'], 'เนื่องจากสถานะของห้องมีการอัปเดตตลอดเวลา ขออนุญาตรับเรื่องให้เจ้าหน้าที่ตรวจสอบสถานะความพร้อมของห้องนี้ แล้วจะรีบติดต่อกลับเพื่อยืนยันให้ทราบทันทีครับ', 10, true, true, 'วันว่าง/เข้าอยู่'),
  ('property'::public.chat_faq_scope, ARRAY['ค่าน้ำค่าไฟ', 'ไฟเรทบ้าน', 'ค่าน้ำหน่วยละ', 'จ่ายไฟที่ไหน', 'water electric', 'ไฟหลวงไหม', 'บิลไฟมายังไง', 'ค่าน้ำแพงไหม', 'จ่ายค่าน้ำนิติ', 'มิเตอร์ไฟ'], 'สำหรับคอนโด ค่าไฟจะคิดตามเรทการไฟฟ้านครหลวง (บิลส่งตรง) ส่วนค่าน้ำจะจ่ายผ่านนิติบุคคลของโครงการครับ เป็นเรทมาตรฐานทั่วไปเลยครับ', 60, true, false, 'ค่าน้ำค่าไฟ'),
  ('property'::public.chat_faq_scope, ARRAY['มีกล้องไหม', 'cctv', 'ความปลอดภัยในห้อง', 'กล้องวงจรปิด', 'security camera', 'ติดกล้องเพิ่มได้ไหม', 'วงจรปิด', 'ดูย้อนหลังกล้อง', 'มีกล้องหน้าห้องไหม'], 'โครงการมีกล้อง CCTV ดูแลความปลอดภัยในพื้นที่ส่วนกลางตลอด 24 ชั่วโมงครับ แต่สำหรับภายในห้องพักจะไม่มีเพื่อความเป็นส่วนตัวของผู้อยู่อาศัยครับ', 90, true, false, 'กล้อง/CCTV'),
  ('property'::public.chat_faq_scope, ARRAY['พาเพื่อนมาได้ไหม', 'มีแขกมาพัก', 'visitors allowed', 'ญาติมานอน', 'ให้คนอื่นเข้า', 'เพื่อนมาหา', 'คนนอกเข้าได้ไหม', 'ที่จอดรถแขก', 'guest parking', 'visitor'], 'สามารถให้ผู้เยี่ยมชมเข้ามาพักหรือเยี่ยมเยียนได้ตามปกติครับ เพียงแต่ต้องปฏิบัติตามกฎระเบียบของนิติบุคคล เช่น การแลกบัตรเข้าออกและการใช้ที่จอดรถ Visitor ครับ', 80, true, false, 'ผู้เยี่ยมชม'),
  ('property'::public.chat_faq_scope, ARRAY['ต่างชาติเช่าได้ไหม', 'foreigner rent', 'chinese allowed', 'ฝรั่งเช่า', 'คนจีนเช่า', 'รับต่างชาติไหม', 'alien quota', 'เช่าชื่อต่างชาติ', 'พาสปอร์ตเช่า', 'foreigner friendly'], 'โดยส่วนใหญ่ยินดีรับชาวต่างชาติครับ แต่บางเจ้าของอาจมีเงื่อนไขเรื่องสัญชาติหรือเอกสารเพิ่มเติมเล็กน้อย แจ้งสัญชาติและฝากเบอร์ไว้ได้เลยครับ ทีมงานจะประสานให้ทันทีครับ', 50, true, false, 'ต่างชาติเช่าได้'),
  ('property'::public.chat_faq_scope, ARRAY['สูบบุหรี่ได้ไหม', 'smoking allowed', 'ดูดบุหรี่', 'สูบระเบียง', 'ห้องสูบบุหรี่', 'สูบพอต', 'กลิ่นบุหรี่', 'ห้ามสูบบุหรี่', 'no smoking', 'ดูดพอตได้ไหม'], 'เพื่อความปลอดภัยและความสะอาด ส่วนใหญ่จะไม่อนุญาตให้สูบบุหรี่ภายในห้องพักครับ บางโครงการอาจมีพื้นที่จัดไว้ให้สูบเฉพาะ เดี๋ยวทีมงานเช็คกฎนิติบุคคลของที่นี่ให้ชัวร์อีกทีนะครับ', 70, true, false, 'สูบบุหรี่'),
  ('property'::public.chat_faq_scope, ARRAY['อยู่ได้กี่คน', 'พักได้สูงสุด', 'max capacity', 'อยู่สามคนได้ไหม', 'คนอยู่เยอะ', 'จำกัดคนไหม', 'ครอบครัวใหญ่', 'พักกี่คน', 'แชร์ห้อง', 'อยู่ 4 คน'], 'จำนวนผู้พักอาศัยจะขึ้นอยู่กับขนาดห้องและข้อกำหนดของแต่ละโครงการครับ เพื่อให้พักอาศัยได้อย่างสบาย แจ้งจำนวนคนมาได้เลยครับ ทีมงานจะช่วยดูว่าเหมาะสมไหม', 80, true, false, 'คนอยู่กี่คน'),
  ('property'::public.chat_faq_scope, ARRAY['มีแอร์ไหม', 'แอร์กี่ตัว', 'appliances', 'มีทีวีไหม', 'มีตู้เย็นไหม', 'ไมโครเวฟ', 'เครื่องใช้ไฟฟ้า', 'แอร์เย็นไหม', 'ล้างแอร์ให้ไหม', 'ทีวีกี่นิ้ว'], 'เบื้องต้นมีเครื่องใช้ไฟฟ้าพื้นฐานให้ตามรูปภาพเลยครับ หากคุณลูกค้าอยากทราบจำนวนแอร์ หรือยี่ห้อเครื่องใช้ไฟฟ้า เพื่อความชัวร์เดี๋ยวเจ้าหน้าที่จะเช็คของจริงหน้างานและรีบแจ้งให้นะครับ', 50, true, false, 'แอร์/เครื่องใช้ไฟฟ้า'),
  ('property'::public.chat_faq_scope, ARRAY['มีค่าใช้จ่ายอื่นไหม', 'hidden fees', 'จ่ายอะไรเพิ่มไหม', 'ค่าขยะ', 'ค่าจอดรถเพิ่ม', 'มีเก็บยิบย่อยไหม', 'รวมเน็ตยัง', 'รวมทำความสะอาดไหม', 'ค่าธรรมเนียมอื่น', 'มีบวกเพิ่มไหม'], 'นอกจากค่าเช่า ค่าน้ำ ค่าไฟ และค่าอินเทอร์เน็ตที่ผู้เช่าต้องรับผิดชอบแล้ว ปกติจะไม่มีค่าใช้จ่ายแอบแฝงครับ แต่เพื่อความสบายใจ ฝากเบอร์ไว้ให้ทีมงานแจกแจงค่าใช้จ่ายทั้งหมดก่อนตัดสินใจได้ครับ', 40, true, false, 'ค่าใช้จ่ายเพิ่มเติม'),
  ('property'::public.chat_faq_scope, ARRAY['ห้องขนาดเท่าไหร่', 'กี่ตารางเมตร', 'พื้นที่ใช้สอย', 'sqm', 'กี่ตรม', 'กี่ตร.ม.', 'ห้องใหญ่ไหม', 'ขนาดกี่ตาราง', 'room size', 'กว้างเท่าไหร่'], 'ขนาดพื้นที่ของห้องจะระบุไว้ที่รายละเอียดหน้าทรัพย์โดยประมาณครับ หากต้องการทราบตัวเลขที่แม่นยำเพื่อเทียบขนาด รบกวนทิ้งเบอร์ไว้ให้ทีมงานเช็คข้อมูลจากโฉนดให้ครับ', 60, true, false, 'ขนาดห้อง/พื้นที่'),
  ('property'::public.chat_faq_scope, ARRAY['ห้องใหม่ไหม', 'เพิ่งทำใหม่', 'รีโนเวทใหม่', 'สภาพห้อง', 'ห้องเก่าไหม', 'renovated', 'รูปจริงไหม', 'ตรงปกไหม', 'มีตำหนิไหม', 'ซ่อมเสร็จยัง'], 'รูปภาพเบื้องต้นเป็นการแสดงสภาพห้องครับ แต่บางห้องอาจเพิ่งมีการปรับปรุงหรือมีผู้เช่าเดิมเพิ่งออก เพื่อความมั่นใจ ทางทีมงานแนะนำให้นัดหมายเข้าไปชมสภาพห้องจริงด้วยตัวเองดีที่สุดครับ', 70, true, false, 'สภาพห้อง/รีโนเวท'),
  ('property'::public.chat_faq_scope, ARRAY['ทำกับข้าวได้ไหม', 'มีเตาไฟฟ้าไหม', 'ครัวปิดไหม', 'มีฮูดดูดควัน', 'cooking', 'มีเครื่องดูดควัน', 'ทำอาหารหนักได้ไหม', 'เตาแก๊ส', 'ครัวเปิด', 'ทำกับข้าว'], 'คอนโดส่วนใหญ่มีพื้นที่ครัวและเตาไฟฟ้าให้ทำอาหารได้เบื้องต้นครับ แต่ไม่แนะนำให้ใช้เตาแก๊สเพื่อความปลอดภัย หากเน้นทำอาหารจริงจัง ลองนัดดูห้องเพื่อดูว่าครัวเป็นแบบปิดระบายอากาศได้ดีหรือไม่ครับ', 80, true, false, 'ทำอาหาร/เตาไฟฟ้า'),
  ('property'::public.chat_faq_scope, ARRAY['มีเน็ตไหม', 'wifi ฟรีไหม', 'ติดเน็ตเอง', 'internet', 'รวมค่าเน็ตไหม', 'เน็ตค่ายไหน', 'ติดไวไฟเพิ่ม', 'มีราวเตอร์', 'มีสายแลนไหม', 'สัญญาณเน็ตดีไหม'], 'ปกติค่าเช่าห้องจะไม่รวมค่าอินเทอร์เน็ตครับ ผู้เช่าสามารถเลือกติดตั้งแพ็กเกจอินเทอร์เน็ตจากผู้ให้บริการต่างๆ ได้เองเลยครับ หากต้องการให้ทีมงานช่วยเช็คคู่สาย ติดต่อแจ้งได้เลยครับ', 60, true, false, 'อินเทอร์เน็ต/Wifi'),
  ('property'::public.chat_faq_scope, ARRAY['มีเครื่องซักผ้าไหม', 'washing machine', 'ซักผ้าที่ไหน', 'มีร้านซักรีดไหม', 'ตู้ซักผ้าหยอดเหรียญ', 'เครื่องซักผ้าฝาหน้า', 'ซักอบ', 'เครื่องอบผ้า', 'เครื่องซักผ้ากี่โล', 'เครื่องซักผ้าส่วนตัว'], 'ห้องพักแต่ละห้องอาจมีหรือไม่มีเครื่องซักผ้าในตัวครับ บางโครงการจะมีห้องซักรีดส่วนกลางให้บริการ หากสนใจห้องนี้ ฝากเบอร์ไว้ให้ทีมงานเช็คสเปกเครื่องซักผ้าให้อีกทีนะครับ', 70, true, false, 'เครื่องซักผ้า'),
  ('property'::public.chat_faq_scope, ARRAY['มีระเบียงไหม', 'ระเบียงกว้างไหม', 'ตากผ้าได้ไหม', 'balcony', 'ซักล้าง', 'แดดเข้าระเบียง', 'ระเบียงติดเน็ตไหม', 'ออกไประเบียง', 'กั้นระเบียง', 'ราวตากผ้า'], 'ส่วนใหญ่จะมีพื้นที่ระเบียงให้สำหรับตากผ้าและวางคอมเพรสเซอร์แอร์ครับ จะกว้างหรือแคบขึ้นอยู่กับเลย์เอาต์ของห้อง นัดดูห้องจริงจะเห็นพื้นที่ใช้งานจริงชัดเจนที่สุดครับ', 80, true, false, 'ระเบียงห้อง'),
  ('property'::public.chat_faq_scope, ARRAY['มีสระว่ายน้ำไหม', 'ฟิตเนสใหญ่ไหม', 'สระเกลือ', 'pool gym', 'facilities', 'ใช้ส่วนกลางฟรีไหม', 'มีห้องสมุด', 'ซาวน่า', 'มีคอร์ทแบดไหม', 'ส่วนกลางมีอะไรบ้าง'], 'โครงการมีสิ่งอำนวยความสะดวกส่วนกลางให้ลูกบ้านใช้งานได้ตามปกติครับ ไม่ว่าจะเป็นสระว่ายน้ำหรือฟิตเนส รายละเอียดว่ามีครบแค่ไหน สามารถให้เจ้าหน้าที่ส่งแคตตาล็อกของโครงการให้ดูเพิ่มเติมได้ครับ', 50, true, false, 'ส่วนกลาง/สระว่ายน้ำ/ฟิตเนส'),
  ('property'::public.chat_faq_scope, ARRAY['มีแม่บ้านไหม', 'มีคนทำความสะอาด', 'cleaning service', 'รวมทำความสะอาด', 'ทำความสะอาดก่อนเข้าอยู่', 'ล้างห้องให้ไหม', 'จ้างแม่บ้าน', 'บิ๊กคลีนนิ่ง', 'มีบริการทำความสะอาด', 'ทำความสะอาดห้อง'], 'ก่อนย้ายเข้า ทางเราจะดูแลให้มีการทำความสะอาดห้องให้พร้อมอยู่ครับ ส่วนระหว่างการเช่า หากต้องการเรียกบริการแม่บ้านทำความสะอาดเพิ่มเติม ก็สามารถเรียกใช้บริการจากแอปภายนอกได้เลยครับ', 60, true, false, 'บริการทำความสะอาด'),
  ('property'::public.chat_faq_scope, ARRAY['ตึกสร้างปีไหน', 'สร้างเสร็จเมื่อไหร่', 'year built', 'คอนโดเก่าไหม', 'อายุกี่ปี', 'สร้างนานยัง', 'โครงการใหม่ไหม', 'พึ่งสร้างเสร็จ', 'ปีที่สร้าง', 'ตึกกี่ปี'], 'ข้อมูลอายุของโครงการมีผลต่อสภาพส่วนกลางครับ หากคุณลูกค้าซีเรียสเรื่องปีที่สร้าง รบกวนทิ้งเบอร์ติดต่อไว้ให้ทีมงานนำข้อมูลเชิงลึกของโครงการนี้มาแจ้งให้ทราบอย่างละเอียดครับ', 80, true, false, 'ปีที่สร้างโครงการ'),
  ('property'::public.chat_faq_scope, ARRAY['วิวอะไร', 'เห็นตึกบังไหม', 'วิวสระไหม', 'ห้องทิศไหน', 'city view', 'วิวแม่น้ำ', 'แดดร้อนไหม', 'ทิศตะวันตก', 'บล็อควิวไหม', 'ทิศเหนือ'], 'เนื่องจากข้อจำกัดในการเปิดเผยตำแหน่งที่แน่นอนของห้อง ทางเราขออนุญาตไม่ระบุทิศหรือวิวแบบเป๊ะๆ ในแชทนี้นะครับ แต่คุณลูกค้าสามารถนัดหมายเข้าไปดูบรรยากาศวิวจากห้องจริงกับทีมงานได้เลยครับ', 10, true, false, 'วิวห้อง'),
  ('property'::public.chat_faq_scope, ARRAY['ปลอดภัยไหม', 'ระบบรักษาความปลอดภัย', 'security', 'มียามกี่คน', 'คีย์การ์ดล็อคชั้นไหม', 'รปภ', 'เข้าออกยังไง', 'ล็อคประตูดิจิตอล', 'digital door lock', 'มีขโมยไหม'], 'โครงการใช้ระบบคีย์การ์ดควบคุมการเข้าออก และมี รปภ. ดูแลตลอด 24 ชั่วโมงครับ หลายห้องมี Digital Door Lock เสริมให้ด้วย ถือว่ามีความปลอดภัยระดับมาตรฐานเลยครับ', 70, true, false, 'ความปลอดภัย'),
  ('discovery'::public.chat_faq_scope, ARRAY['ขอดูห้อง', 'นัดดูห้อง', 'ไปดูจริงได้ไหม', 'view room', 'book viewing', 'อยากเห็นห้องจริง', 'เข้าไปดูวันเสาร์', 'นัดชมห้อง', 'ขอดูสถานที่', 'ว่างให้ดูไหม'], 'ยินดีให้บริการนัดชมห้องจริงครับ รบกวนคุณลูกค้าฝากชื่อ เบอร์โทรศัพท์ และวันเวลาที่สะดวกไว้ได้เลยครับ ทีมงานจะประสานงานจองคิวพาเข้าชมให้อย่างรวดเร็วครับ', 10, true, true, 'นัดดูห้อง'),
